var now = new Date();
var timestamp = now.toISOString().replace(/[:.]/g, '-');
var dateStr = now.toISOString().split('T')[0];
var label = $.input.backupLabel || 'workflow-backup';
var fileName = label + '-' + timestamp + '.json';
var backupContent = '';
try {
  var parsed = JSON.parse($.input.backupData);
  var wrapper = {
    backupMetadata: {
      label: label,
      createdAt: now.toISOString(),
      source: 'One CLI Backup Flow'
    },
    data: parsed
  };
  backupContent = JSON.stringify(wrapper, null, 2);
} catch(e) {
  backupContent = $.input.backupData;
}
return { fileName: fileName, content: backupContent, dateStr: dateStr, contentSize: backupContent.length };

var backup = $.steps.prepareBackup.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Backup Complete', emoji: true } });
var sizeKb = Math.round(backup.contentSize / 1024);
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*File:*\n' + backup.fileName },
  { type: 'mrkdwn', text: '*Size:*\n' + sizeKb + ' KB' }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Date:*\n' + backup.dateStr },
  { type: 'mrkdwn', text: '*Label:*\n' + ($.input.backupLabel || 'workflow-backup') }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Backed up to Google Drive via One CLI' }] });
var fallback = 'Backup complete: ' + backup.fileName + ' (' + sizeKb + ' KB)';
return { blocks: blocks, fallback: fallback };
